class TweetCounts {
    private Map<String, TreeMap<Integer, Integer>> tweetMap;

    public TweetCounts() {
        tweetMap = new HashMap<>();
    }

    public void recordTweet(String tweetName, int time) {
        tweetMap.computeIfAbsent(tweetName, k -> new TreeMap<>()).put(time, tweetMap.getOrDefault(tweetName, new TreeMap<>()).getOrDefault(time, 0) + 1);
    }

    public List<Integer> getTweetCountsPerFrequency(String freq, String tweetName, int startTime, int endTime) {
        int chunkSize = freq.equals("minute") ? 60 : freq.equals("hour") ? 3600 : 86400;
        List<Integer> res = new ArrayList<>();
        TreeMap<Integer, Integer> timeMap = tweetMap.getOrDefault(tweetName, new TreeMap<>());
        int startChunk = startTime - startTime % chunkSize, endChunk = endTime - endTime % chunkSize;
        for (int i = startChunk; i <= endChunk; i += chunkSize) {
            int count = 0;
            for (int j = i; j < i + chunkSize && j <= endTime; j++) {
                count += timeMap.getOrDefault(j, 0);
            }
            res.add(count);
        }
        return res;
    }
}
```
